diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..8ccdcae6e07b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5155,6 +5155,76 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
     }
   }

+  // icmp pred (X / C), X
+  // icmp pred X, (X / C)
+  // Also handle logical/arithmetic right shift as they are analogous to
+  // unsigned/signed division.
+  BinaryOperator *Div = nullptr;
+  bool DivOnLHS;
+  if (BO0 && Op1 == BO0->getOperand(0)) {
+    switch (BO0->getOpcode()) {
+    case Instruction::SDiv:
+    case Instruction::UDiv:
+    case Instruction::LShr:
+    case Instruction::AShr:
+      Div = BO0;
+      DivOnLHS = true;
+      break;
+    default:
+      break;
+    }
+  } else if (BO1 && Op0 == BO1->getOperand(0)) {
+    switch (BO1->getOpcode()) {
+    case Instruction::SDiv:
+    case Instruction::UDiv:
+    case Instruction::LShr:
+    case Instruction::AShr:
+      Div = BO1;
+      DivOnLHS = false;
+      break;
+    default:
+      break;
+    }
+  }
+  if (Div) {
+    const APInt *DivC;
+    if (match(Div->getOperand(1), m_APInt(DivC))) {
+      bool IsValid = false;
+      unsigned Opcode = Div->getOpcode();
+      if (Opcode == Instruction::SDiv) {
+        // For sdiv, exclude 1 (no-op) and -1 (may overflow).
+        // Allow equality and signed predicates.
+        IsValid = !DivC->isOne() && !DivC->isAllOnes() &&
+                  !CmpInst::isUnsigned(Pred);
+      } else if (Opcode == Instruction::UDiv) {
+        // For udiv, exclude 1 (no-op).
+        IsValid = !DivC->isOne();
+      } else if (Opcode == Instruction::LShr) {
+        // For lshr, exclude 0 (no-op).
+        IsValid = !DivC->isZero();
+      } else if (Opcode == Instruction::AShr) {
+        // For ashr, exclude 0 (no-op).
+        // Only allow slt/sge (or sgt/sle when on RHS) because ashr of -1
+        // equals -1, which breaks the equivalence for sle/sgt and eq/ne.
+        if (!DivC->isZero()) {
+          if (DivOnLHS)
+            IsValid = (Pred == ICmpInst::ICMP_SLT ||
+                       Pred == ICmpInst::ICMP_SGE);
+          else
+            IsValid = (Pred == ICmpInst::ICMP_SGT ||
+                       Pred == ICmpInst::ICMP_SLE);
+        }
+      }
+      if (IsValid) {
+        // icmp pred (X / C), X --> icmp swapped(pred) X, 0
+        // icmp pred X, (X / C) --> icmp pred X, 0
+        ICmpInst::Predicate NewPred =
+            DivOnLHS ? I.getSwappedPredicate() : Pred;
+        return new ICmpInst(NewPred, Div->getOperand(0),
+                            Constant::getNullValue(Div->getType()));
+      }
+    }
+  }
   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
       (BO0->hasOneUse() || BO1->hasOneUse()) &&
       BO0->getOperand(1) == BO1->getOperand(1)) {

